// --- Update User Password Cloud Function (Callable) ---
exports.updateUserPassword = functions.https.onCall(async (data, context) => {
  // Check if the user is an admin
  if (!context.auth || context.auth.token.role !== 'admin') {
    throw new functions.https.HttpsError(
      'permission-denied',
      'Only admin users can change passwords.'
    );
  }

  const { uid, newPassword } = data;
  if (!uid || !newPassword) {
    throw new functions.https.HttpsError(
      'invalid-argument',
      'The function must be called with \"uid\" and \"newPassword\" arguments.'
    );
  }

  try {
    // Update the password in Firebase Authentication
    await admin.auth().updateUser(uid, { password: newPassword });
    return { message: `Password for user \${uid} updated successfully.` };
  } catch (error) {
    console.error(\"Error updating password:\", error);
    throw new functions.https.HttpsError(
      'internal',
      'An error occurred while updating the password.'
    );
  }
});
